<tr data-mp="adestramento de animais animais animais" data-desc="O adestrador ensina comandos e comportamentos a animais — principalmente cães — usando reforço positivo. Atua em pet shops, canis, haras ou de forma autônoma. Áreas especializadas incluem cães-guia, animais de terapia e farejamento."><td style="text-align:center;padding:6px 4px">☐</td><td class="mp-pnome" style="padding:6px 12px;font-size:13px" onclick="(function(td){var tr=td.closest('tr');if(!tr.dataset.desc)return;var nx=tr.nextElementSibling;if(nx&&nx.classList.contains('mp-det')){nx.remove();return;}var d=document.createElement('tr');d.className='mp-det';d.innerHTML='<td></td><td colspan=2>'+tr.dataset.desc+'</td>';tr.parentNode.insertBefore(d,tr.nextSibling)})(this)">Adestramento de animais <span class="mp-a-ani">Animais</span></td><td style="padding:6px 8px"><span class="mp-cl">Livre</span></td></tr>
